function solve(nums) {
    const N = nums.length;
    if (N === 0) {
        return [];
    }
    if (N === 1) {
        return [nums[0]];
    }

    // 1. Calculate L: L[i] is the maximum element strictly to the left of index i.
    const L = new Array(N).fill(0);
    // Since nums[i] >= 1, initializing L[0] to 0 ensures nums[0] > L[0] is always false 
    // (unless nums[0] was 0, but constraints say >= 1). This is safe for the boundary check logic.

    let currentMax = nums[0];
    L[1] = nums[0]; 

    for (let i = 2; i < N; i++) {
        currentMax = Math.max(currentMax, nums[i - 1]);
        L[i] = currentMax;
    }
    // Correction for initialization simplicity: let's re-run L calculation based on the derived iterative definition
    L.fill(0);
    for (let i = 1; i < N; i++) {
        L[i] = Math.max(L[i-1], nums[i-1]);
    }


    // 2. Calculate R: R[i] is the maximum element strictly to the right of index i.
    const R = new Array(N).fill(0);
    // R[N-1] remains 0
    for (let i = N - 2; i >= 0; i--) {
        R[i] = Math.max(R[i+1], nums[i+1]);
    }

    const result = [];

    // 3. Check validity
    for (let i = 0; i < N; i++) {
        // First and last elements are always valid
        if (i === 0 || i === N - 1) {
            result.push(nums[i]);
            continue;
        }

        // Check condition A: strictly greater than all elements to its left
        const conditionA = nums[i] > L[i];

        // Check condition B: strictly greater than all elements to its right
        const conditionB = nums[i] > R[i];

        // Valid if A OR B is true
        if (conditionA || conditionB) {
            result.push(nums[i]);
        }
    }

    return result;
}

